parameters.jsCode:
// Claude was asked for pure JSON, but parse defensively.
const text = $json.content?.[0]?.text ?? '';
let essay = '', quote = '';
try {
  const cleaned = text.replace(/^```(json)?\s*/i, '').replace(/```\s*$/, '').trim();
  const parsed = JSON.parse(cleaned);
  essay = parsed.essay || '';
  quote = parsed.quote || '';
} catch (e) {
  essay = text.trim();
}
if (!essay) essay = 'The resident essayist stared at the wall and produced nothing. Commission again.';
return [{ json: { essay, quote } }];
